const all = $input.all().map(i => i.json);
const date = all[0]?.date || 'unknown';

let html = `<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;max-width:640px;margin:0 auto;padding:24px;">`;
html += `<h1 style="font-size:22px;color:#1a1a1a;margin-bottom:4px;">📄 HF Daily Papers — ${date}</h1>`;
html += `<p style="color:#6b7280;font-size:14px;margin-bottom:20px;">오늘의 인기 논문 Top ${all.length}편</p>`;

for (let i = 0; i < all.length; i++) {
  const p = all[i];
  if (!p.paper_id) continue;
  html += `<div style="margin-bottom:16px;padding:14px 16px;border:1px solid #e5e7eb;border-radius:10px;">`;
  html += `<div style="font-size:15px;font-weight:600;"><a href="${p.url}" style="color:#6c2bd9;text-decoration:none;">${i+1}. ${p.title}</a></div>`;
  html += `<div style="font-size:12px;color:#6b7280;margin-top:4px;">⬆️ ${p.upvotes} upvotes${p.authors ? ' · ' + p.authors : ''}</div>`;
  html += `</div>`;
}

html += `<hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">`;
html += `<p style="color:#9ca3af;font-size:12px;">Powered by <a href="https://www.upstage.ai" style="color:#6c2bd9;">Upstage</a> · <a href="https://huggingface.co/papers" style="color:#6c2bd9;">HuggingFace Daily Papers</a></p>`;
html += `</div>`;

return [{ json: {
  date,
  subject: `📄 HF Daily Papers — ${date} (${all.length}편)`,
  html,
  count: all.length
} }];

const dateStr = new Date(Date.now() - 86400000).toISOString().slice(0,10);
let papers = [];

// Handle all possible n8n HTTP response formats
const raw = $input.first().json;
try {
  if (Array.isArray(raw)) papers = raw;
  else if (Array.isArray(raw?.body)) papers = raw.body;
  else if (typeof raw === 'string') papers = JSON.parse(raw);
  else if (typeof raw?.body === 'string' && raw.body.trim().startsWith('[')) papers = JSON.parse(raw.body);
  else {
    // n8n may auto-parse the JSON array into numbered keys
    const keys = Object.keys(raw).filter(k => !isNaN(k));
    if (keys.length > 0) {
      papers = keys.map(k => raw[k]);
    }
  }
} catch (e) {}

if (!papers.length) {
  return [{ json: { date: dateStr, paper_id: 'none', title: 'No papers found for ' + dateStr, url: '#', upvotes: 0 } }];
}

papers.sort((a,b) => (b.paper?.upvotes||0) - (a.paper?.upvotes||0));
return papers.slice(0, 10).map(p => ({
  json: {
    date: dateStr,
    paper_id: p.paper?.id || '',
    title: p.paper?.title || 'Untitled',
    url: 'https://huggingface.co/papers/' + (p.paper?.id || ''),
    upvotes: p.paper?.upvotes || 0,
    authors: (p.paper?.authors || []).map(a => a.name || a.user || '').filter(Boolean).slice(0,3).join(', ')
  }
}));
